patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 703065280096..a1f343f17e22 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -3122,6 +3122,20 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
   if (Value *V = foldIsPowerOf2OrZero(RHS, LHS, IsAnd, Builder))
     return V;

+  // (icmp ult (add A, B), A) | (icmp ult (add A, B), B) --> (icmp ult (add A, B), A)
+  // (icmp ult (add A, B), A) | (icmp ult (add A, B), B) is just the UAddo check.
+  // One of the operands is redundant.
+  // We can handle both directions for both And and Or here.
+  // And case is: (icmp uge (add A, B), A) & (icmp uge (add A, B), B) -> (icmp uge (add A, B), A)
+  {
+    Value *A, *B, *A2, *B2;
+    Value *S1, *S2;
+    if (match(LHS, m_UAddWithOverflow(m_Value(A), m_Value(B), m_Value(S1))) &&
+        match(RHS, m_UAddWithOverflow(m_Value(A2), m_Value(B2), m_Value(S2))) &&
+        S1 == S2 && ((A == A2 && B == B2) || (A == B2 && B == A2)))
+      return LHS;
+  }
+
   // TODO: One of these directions is fine with logical and/or, the other could
   // be supported by inserting freeze.
   if (!IsLogical) {
